import React, { useState } from "react";
import { ArrowUpRight } from "lucide-react";

export default function DepositScreen({ onDeposit, goBack }) {
  const [amount, setAmount] = useState("");

  const handleDeposit = () => {
    if (!amount || isNaN(amount) || amount <= 0) {
      alert("Enter a valid amount");
      return;
    }
    onDeposit(parseFloat(amount));
    setAmount("");
  };

  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen animate-fade-in">
      {/* Back Button */}
      <button
        onClick={goBack}
        className="mb-6 text-teal-600 font-medium flex items-center gap-2"
      >
        ← Back
      </button>

      <h1 className="text-2xl font-bold mb-6 text-gray-800">Deposit Funds</h1>

      <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-md space-y-4">
        <input
          type="number"
          placeholder="Enter amount"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          className="w-full border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-emerald-500"
        />

        <button
          onClick={handleDeposit}
          className="w-full flex items-center justify-center gap-2 py-3 bg-gradient-to-r from-emerald-600 to-teal-700 text-white rounded-xl hover:opacity-90 transition-opacity"
        >
          <ArrowUpRight className="w-5 h-5" /> Deposit
        </button>
      </div>
    </div>
  );
}
